    vector<int> parent;
    // parity_to_root[i] stores the parity of the path weight from node i to parent[i].
    // 0 means even weight path, 1 means odd weight path.
    vector<int> parity_to_root; 
    int n;

    DSU(int size) : n(size) {
        parent.resize(n);
        iota(parent.begin(), parent.end(), 0); // parent[i] = i
        parity_to_root.assign(n, 0); // Initially, path weight to self is 0 (even)
    }

    // Finds the representative of the set containing i, and performs path compression.
    // Also updates parity_to_root[i] to reflect the parity of the path from i to the ultimate root.
    pair<int, int> find(int i) {
        if (parent[i] == i) {
            return {i, 0}; // Root, path parity to itself is 0
        }

        // Recursive call to find the root and the parity from parent[i] to the root
        pair<int, int> root_info = find(parent[i]);
        int root = root_info.first;
        int parity_p_to_root = root_info.second;

        // Path compression: set parent[i] directly to the root
        parent[i] = root;

        // Update parity_to_root[i]: 
        // New parity(i -> root) = parity(i -> old_parent) + parity(old_parent -> root) (mod 2)
        // parity(i -> old_parent) is stored in parity_to_root[i] before the update.
        parity_to_root[i] = (parity_to_root[i] + parity_p_to_root) % 2;

        return {root, parity_to_root[i]};
    }

    // Tries to unite the sets containing u and v with an edge of weight w.
    // Returns true if the edge is added (i.e., no cycle is formed with odd weight), false otherwise.
    bool unite(int u, int v, int w) {
        pair<int, int> root_u_info = find(u);
        int root_u = root_u_info.first;
        int parity_u_to_root_u = root_u_info.second;

        pair<int, int> root_v_info = find(v);
        int root_v = root_v_info.first;
        int parity_v_to_root_v = root_v_info.second;

        if (root_u != root_v) {
            // No cycle formed. Merge the two sets (e.g., attach root_v to root_u)
            parent[root_v] = root_u;

            // We need to set parity_to_root[root_v] such that:
